svg.script:

var scenes = ['s0','s1','s2','s3','s4','s5','s6','s7','s8','s9'];
var current = 0;
var transitioning = false;

function showPrompt() {
  var p = document.getElementById('clickPrompt');
  if (p && current < scenes.length - 1) p.setAttribute('opacity', '1');
}

function hidePrompt() {
  var p = document.getElementById('clickPrompt');
  if (p) p.setAttribute('opacity', '0');
}

// Show click prompt after first scene loads
setTimeout(showPrompt, 2000);

document.querySelector('.click-area').addEventListener('click', function() {
  if (transitioning) return;
  if (current >= scenes.length - 1) {
    // Reset to beginning
    var last = document.getElementById(scenes[current]);
    if (last) last.setAttribute('class', 'scene');
    current = 0;
    var first = document.getElementById(scenes[0]);
    if (first) first.setAttribute('class', 'scene active');
    setTimeout(showPrompt, 2000);
    return;
  }

  transitioning = true;
  hidePrompt();

  // Fade out current
  var cur = document.getElementById(scenes[current]);
  if (cur) cur.setAttribute('class', 'scene exit');

  // Fade in next
  setTimeout(function() {
    if (cur) cur.setAttribute('class', 'scene');
    current++;
    var next = document.getElementById(scenes[current]);
    if (next) next.setAttribute('class', 'scene active');
    transitioning = false;

    // Show prompt after animations settle
    if (current < scenes.length - 1) {
      setTimeout(showPrompt, 2500);
    }
  }, 800);
});
